import{_ as e,o,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const s=JSON.parse('{"title":"G04: 核心產品與競爭優勢 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G04_核心產品與競爭優勢_投資研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G04_核心產品與競爭優勢_投資研究員.md"}'),r={name:"審計報告庫/經營審計/3189_景碩/20260423/G04_核心產品與競爭優勢_投資研究員.md"};function l(d,a,n,_,c,h){return o(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="g04-核心產品與競爭優勢-投資研究員-審計報告" tabindex="-1">G04: 核心產品與競爭優勢 - 投資研究員 審計報告 <a class="header-anchor" href="#g04-核心產品與競爭優勢-投資研究員-審計報告" aria-label="Permalink to &quot;G04: 核心產品與競爭優勢 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>公司的核心產品與服務為何？針對的目標客群是誰？對比同業具備何種技術或成本優勢？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩核心產品為ABF載板（營收佔比約40%）、BT載板（30-40%）及晶碩光學隱形眼鏡（20-30%）。核心競爭優勢在於全球BT載板最大供應商地位，享有規模與良率優勢，同時NVIDIA CPU載板供應份額從5%持續攀升至50%。惟ABF高階市場由日商Ibiden主導（GB200佔約70%），景碩技術位階屬第二梯隊。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A-（良偏弱）。BT載板護城河明確且穩定（全球第一，市佔20-25%）；ABF領域仍在追趕中（全球第四，市佔12%）。合併毛利率22.13%介於同業中段（欣興25-28%、南電18-22%、Ibiden 30%+），差距源於高階ABF產品佔比不足。ABF載板毛利率約18-22%低於Ibiden的30%+，但隨著高階佔比提升正在收窄中。未來獲利結構改善的關鍵在於ABF載板高階產品出貨佔比能否從35%提升至50%+。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>2025年產品組合按終端應用分為：手機36%（BT載板+SiP載板）、HPC 23%（ABF GPU/CPU）、消費性16%、隱形眼鏡18%、基地台7%。客戶涵蓋NVIDIA、AMD、Qualcomm、Broadcom、MediaTek等全球Tier 1晶片設計公司，終端觸及Apple、Samsung。NVIDIA CPU載板供貨率從2023年約5%急升至2025年約50%，景碩在AI供應鏈的滲透正在加速。BT載板領域景碩是全球最大供應商，年產能領先，這是其最堅實的護城河。</p><p>毛利率階差定量審計：對比欣興同季毛利率約25-28%，景碩低3-5個百分點；對比Ibiden約30%+則低8-10個百分點。關鍵限制因素包括(1)BT載板毛利率本質偏低約15-18%，拖累整體毛利率 (2)ABF高階產品（14L+）佔比僅35%，仍低於欣興45%和Ibiden 70% (3)晶碩光學受美元匯率曝險影響（營收80%以美元計價、成本僅50%為美元），新台幣每升值5%對集團毛利率約-0.5%。</p><p>2026年展望：法說會預期毛利率可逐季提升，主因ABF載板產能利用率維持&gt;90%+ASIC訂單高毛利率貢獻。若Google TPU v6量產順利，預估2026年Q4毛利率可挑戰25%，全年平均約22-24%。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的競爭力雙軌並存：BT載板全球龍頭地位難以撼動——載板產業資本投入巨大（一條產線&gt;100億元），新進者追趕難度高；ABF載板則需透過產能擴張和認證深化逐步提升供貨份額。最大風險是ABF供需若因AI放緩反轉，擴產投資（235億元六廠）將造成折舊壓力。若玻璃基板提前商業化，現有ABF/BT產線可能有技術汰換壓力。</p><p>最需跟蹤的競爭力指標：當季ABF載板毛利率與欣興/Ibiden的差距變化——差距持續縮小則證明景碩的追趕策略有效。2025年ABF毛利率約18-22%對比Ibiden 30%+差距約8-12個百分點，目標2027年縮至5-8個百分點。</p><p>中長期競爭風險來自技術代差。若Ibiden在20L ABF載板量產上取得完全領先（預計2027年），景碩可能被迫以價格競爭維持ABF載板市佔率，導致毛利率持續低於同業。景碩應加速ASIC客戶（Google/Broadcom）的載板設計研發，以多元化客戶結構減少對價格戰的依賴。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>FinMind財務數據</code>: 2025年全年營收108.11億元、毛利率22.13%</li><li><code>優分析</code>: 景碩BT載板全球最大供應商地位、NVIDIA CPU供貨率50%</li><li><code>富果法說會備忘錄</code>: 2025年產品組合與終端應用佔比</li><li><code>MoneyDJ</code>: ABF/BT/隱形眼鏡營收佔比數據</li><li><code>今周刊</code>: 全球BT載板供應商排名分析</li></ul>',17)])])}const p=e(r,[["render",l]]);export{s as __pageData,p as default};
